package com.Array;

public class CustomerDetailForEach {

	public static void main(String[] args) {
		// TODO Auto-generated method stub
		String marks[]=new String[5];
		marks[0]="Harini";
		marks[1]="Kavin";
		marks[2]="Jesica";
		marks[3]="Raja";
		marks[4]="Aaron";
		for(String i:marks) {
			System.out.println(i);
		}

	}
	

}
